import React, { useEffect } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import Layout from '../../components/shared/Layout';
import { fetchMyTransactions } from '../../store/slices/transactionSlice';

export default function TransactionsPage() {
  const dispatch = useDispatch();
  const { transactions, loading } = useSelector(s => s.transactions);

  useEffect(() => { dispatch(fetchMyTransactions()); }, [dispatch]);

  return (
    <Layout>
      <div className="pt-5 pt-md-0">
        <h2 className="mb-4" style={{ color: '#1e293b' }}>📒 Passbook</h2>
      </div>
      {loading ? <p>Loading...</p> : (
        <div style={{ background: '#fff', borderRadius: 12, overflow: 'hidden', boxShadow: '0 2px 8px rgba(0,0,0,0.06)' }}>
          {/* Horizontal scroll wrapper for mobile */}
          <div className="table-responsive">
            <table className="table table-hover mb-0" style={{ minWidth: 700 }}>
              <thead style={{ background: '#f8fafc' }}>
                <tr>
                  {['Date', 'Account', 'Description', 'Ref ID', 'Category', 'Amount', 'Balance After'].map(h => (
                    <th key={h} style={{ padding: '14px 16px', fontSize: 13, fontWeight: 700, color: '#475569', borderBottom: '1px solid #e2e8f0' }}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {transactions.length === 0 && (
                  <tr><td colSpan={7} className="text-center py-4" style={{ color: '#94a3b8' }}>No transactions yet</td></tr>
                )}
                {transactions.map(txn => (
                  <tr key={txn.txnId} style={{ borderBottom: '1px solid #f1f5f9' }}>
                    <td style={{ padding: '12px 16px', fontSize: 13, color: '#64748b' }}>{new Date(txn.date).toLocaleDateString('en-IN')}</td>
                    <td style={{ padding: '12px 16px', fontSize: 13, fontFamily: 'monospace' }}>{txn.accountNumber}</td>
                    <td style={{ padding: '12px 16px', fontSize: 13 }}>{txn.description}</td>
                    <td style={{ padding: '12px 16px', fontSize: 12, color: '#94a3b8', fontFamily: 'monospace' }}>{txn.referenceId || txn.txnId}</td>
                    <td style={{ padding: '12px 16px' }}>
                      <span style={{ fontSize: 11, padding: '2px 8px', borderRadius: 99, background: '#f1f5f9', color: '#475569' }}>{txn.transactionCategory}</span>
                    </td>
                    <td style={{ padding: '12px 16px', fontWeight: 700, color: txn.type === 'CREDIT' ? '#22c55e' : '#ef4444' }}>
                      {txn.type === 'CREDIT' ? '+' : '-'} ₹{txn.amount?.toLocaleString('en-IN')}
                    </td>
                    <td style={{ padding: '12px 16px', fontWeight: 600, color: '#1e293b' }}>₹{txn.balanceAfterTxn?.toLocaleString('en-IN')}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}
    </Layout>
  );
}
